53	
54	DLDevice getDLDevice(const Tensor& tensor)
55	{
56	    int device_id = 0;
57	    if (tensor.device().type == ft::kDEVICE) {
58	        cudaPointerAttributes ptr_attr{};
59	        cudaPointerGetAttributes(&ptr_attr, tensor.raw_data());
60	        device_id = ptr_attr.device;
61	    }
62	
63	    DLDevice device{kDLCPU, device_id};
64	
65	    switch (tensor.device().type) {
66	        case ft::kCPU:
67	            device.device_type = DLDeviceType::kDLCPU;
68	            break;
69	        case ft::kCPUpinned:
70	            device.device_type = DLDeviceType::kDLCUDAHost;
71	            break;
72	        case ft::kDEVICE:
73	            device.device_type = DLDeviceType::kDLCUDA;
74	            break;
75	        default:
76	            break;
77	    }
78	
79	    return device;
80	}
81	
82	DLManagedTensor* TritonTensorToDLManagedTensor(Tensor& tensor)
83	{
84	    DLDevice   device = getDLDevice(tensor);
85	    DLDataType data_type{0, 0, 1};
86	    using ft::data_type_v;
87	    switch (tensor.dtype()) {
88	        case data_type_v<bool>:
89	            data_type.code = DLDataTypeCode::kDLBool;
90	            data_type.bits = 8;
91	            break;
92	        case data_type_v<uint8_t>:
93	            data_type.code = DLDataTypeCode::kDLUInt;
94	            data_type.bits = 8;
95	            break;
96	        case data_type_v<uint16_t>:
97	            data_type.code = DLDataTypeCode::kDLUInt;
98	            data_type.bits = 16;
99	            break;
100	        case data_type_v<uint32_t>:
101	            data_type.code = DLDataTypeCode::kDLUInt;
102	            data_type.bits = 32;
103	            break;
104	        case data_type_v<uint64_t>:
105	            data_type.code = DLDataTypeCode::kDLUInt;
106	            data_type.bits = 64;
107	            break;
108	        case data_type_v<int8_t>:
109	            data_type.code = DLDataTypeCode::kDLInt;
110	            data_type.bits = 8;
111	            break;
112	        case data_type_v<int16_t>:
113	            data_type.code = DLDataTypeCode::kDLInt;
114	            data_type.bits = 16;
115	            break;
116	        case data_type_v<int32_t>:
117	            data_type.code = DLDataTypeCode::kDLInt;
118	            data_type.bits = 32;
119	            break;
120	        case data_type_v<int64_t>:
121	            data_type.code = DLDataTypeCode::kDLInt;
122	            data_type.bits = 64;
123	            break;
124	        case data_type_v<turbomind::half_t>:
125	            data_type.code = DLDataTypeCode::kDLFloat;
126	            data_type.bits = 16;
127	            break;
128	        case data_type_v<float>:
129	            data_type.code = DLDataTypeCode::kDLFloat;
130	            data_type.bits = 32;
131	            break;
132	        case data_type_v<double>:
133	            data_type.code = DLDataTypeCode::kDLFloat;
134	            data_type.bits = 64;
135	            break;
136	        case data_type_v<turbomind::bfloat16_t>:
137	            data_type.code = DLDataTypeCode::kDLBfloat;
138	            data_type.bits = 16;
139	            break;
140	        default:
141	            break;
142	    }
143	
144	    static_assert(sizeof(int64_t) == sizeof(tensor.shape(0)));
145	
146	    Tensor*  ctx = new Tensor(tensor);
147	    DLTensor dl_tensor{const_cast<void*>(ctx->raw_data()),
148	                       device,
149	                       (int32_t)(ctx->ndim()),
150	                       data_type,
151	                       (int64_t*)ctx->shape().data(),
152	                       (int64_t*)(nullptr),
153	                       0};
154	    return new DLManagedTensor{dl_tensor, ctx, [](DLManagedTensor* dlmt) {  //
155	                                   delete (Tensor*)dlmt->manager_ctx;
156	                                   delete dlmt;
157	                               }};
158	}
159	
160	ft::DeviceType getMemoryType(DLDevice device)
161	{
162	    switch (device.device_type) {
163	        case DLDeviceType::kDLCUDAHost:
164	            return ft::DeviceType::kCPUpinned;
165	        case DLDeviceType::kDLCUDA:
166	            return ft::DeviceType::kDEVICE;
167	        case DLDeviceType::kDLCPU:
168	        default:
169	            return ft::DeviceType::kCPU;
170	    }
171	}
172	
173	ft::DataType getDataType(DLDataType data_type)
174	{
175	    using ft::data_type_v;
176	    switch (data_type.code) {
177	        case DLDataTypeCode::kDLUInt:
178	            switch (data_type.bits) {
179	                case 8:
180	                    return data_type_v<uint8_t>;
181	                case 16:
182	                    return data_type_v<uint16_t>;
183	                case 32:
184	                    return data_type_v<uint32_t>;
185	                case 64:
186	                    return data_type_v<uint64_t>;
187	                default:
188	                    return data_type_v<void>;
189	            }
190	            break;
191	        case DLDataTypeCode::kDLInt:
192	            switch (data_type.bits) {
193	                case 8:
194	                    return data_type_v<int8_t>;
195	                case 16:
196	                    return data_type_v<int16_t>;
197	                case 32:
198	                    return data_type_v<int32_t>;
199	                case 64:
200	                    return data_type_v<int64_t>;
201	                default:
202	                    return data_type_v<void>;
203	            }
204	            break;
205	        case DLDataTypeCode::kDLFloat:
206	            switch (data_type.bits) {
207	                case 16:
208	                    return data_type_v<turbomind::half_t>;
209	                case 32:
210	                    return data_type_v<float>;
211	                case 64:
212	                    return data_type_v<double>;
213	                default:
214	                    return data_type_v<void>;
215	            }
216	            break;
217	        case DLDataTypeCode::kDLBfloat:
218	            switch (data_type.bits) {
219	                case 16:
220	                    return data_type_v<turbomind::bfloat16_t>;
221	                default:
222	                    return data_type_v<void>;
223	            }
224	            break;
225	        case DLDataTypeCode::kDLBool:
226	            return data_type_v<bool>;
227	        default:
228	            return data_type_v<void>;
229	    }
230	}
231	
232	std::shared_ptr<Tensor> DLManagedTensorToTritonTensor(DLManagedTensor* tensor)
233	{
234	    auto& dl_tensor = tensor->dl_tensor;
235	    auto  where     = getMemoryType(dl_tensor.device);
236	    auto  dtype     = getDataType(dl_tensor.dtype);
237	    assert(dl_tensor.ndim > 0);
238	    std::vector<ft::core::ssize_t> shape(dl_tensor.shape, dl_tensor.shape + dl_tensor.ndim);
239	
240	    std::shared_ptr<void> ptr{dl_tensor.data, [tensor](void* p) {
241	                                  if (tensor->deleter) {
242	                                      tensor->deleter(tensor);
243	                                  }
244	                              }};
245	    return std::make_shared<Tensor>(ptr, std::move(shape), dtype, where);
246	}
247	
248	static void safe_memcpy(void* dst, const void* src, size_t size)
249	{
250	    cudaPointerAttributes dat{};
251	    cudaPointerAttributes sat{};
252	    TM_CUDA_CHECK(cudaPointerGetAttributes(&dat, dst));
253	    TM_CUDA_CHECK(cudaPointerGetAttributes(&sat, src));
254	    try {
255	        if (dat.devicePointer && sat.devicePointer) {
256	            // Both can be accessed from current context
257	            TM_CUDA_CHECK(cudaMemcpy(dst, src, size, cudaMemcpyDefault));
258	        }
259	        else if (dat.type == cudaMemoryTypeDevice && sat.type == cudaMemoryTypeDevice) {
260	            if (dat.device != sat.device) {
261	                // On different devices, try peer memcpy
262	                TM_CUDA_CHECK(cudaMemcpyPeer(dst, dat.device, src, sat.device, size));
263	            }
264	            else {
265	                // Same device, switch to the device first (this is unlikely)
266	                ft::CudaDeviceGuard guard(dat.device);
267	                TM_CUDA_CHECK(cudaMemcpy(dst, src, size, cudaMemcpyDefault));
268	            }
269	        }
270	        else {
271	            // Unknown case, give it a try anyway
272	            TM_CUDA_CHECK(cudaMemcpy(dst, src, size, cudaMemcpyDefault));
273	        }
274	    }
275	    catch (...) {
276	        int device_id{-1};
277	        cudaGetDevice(&device_id);
278	        TM_LOG_ERROR("cudaMemcpy failed: dst=({}, {}, {}, {}), src=({}, {}, {}, {}), size={}, device={}",
279	                     (int)dat.type,
280	                     dat.device,
281	                     dat.devicePointer,
282	                     dat.hostPointer,
283	                     (int)sat.type,
284	                     sat.device,
